// eslint.config.js
import js from '@eslint/js'
import tseslint from 'typescript-eslint'
import reactHooks from 'eslint-plugin-react-hooks'
import reactRefresh from 'eslint-plugin-react-refresh'

export default tseslint.config(
  { ignores: ['dist', 'public/data'] },
  {
    extends: [
      js.configs.recommended,
      ...tseslint.configs.recommended,
    ],
    files: ['**/*.{ts,tsx}'],
    plugins: {
      'react-hooks': reactHooks,
      'react-refresh': reactRefresh,
    },
    rules: {
      ...reactHooks.configs.recommended.rules,
      'react-refresh/only-export-components': ['warn', { allowConstantExport: true }],
    },
  }
)

// ESLint error: React Hook useEffect has missing dependency 'userId'
useEffect(() => {
  fetchUser(userId)  // userId is referenced but not in deps
}, [])              // <-- eslint: add 'userId'

// Fixed:
useEffect(() => {
  fetchUser(userId)
}, [userId])        // re-runs whenever userId changes

import prettierConfig from 'eslint-config-prettier'

export default tseslint.config(
  // ... previous config ...
  prettierConfig  // must be last — disables conflicting ESLint rules
)

{
  "scripts": {
    "lint": "eslint . --max-warnings 0",
    "lint:fix": "eslint . --fix",
    "format": "prettier --write .",
    "format:check": "prettier --check .",
    "ci": "npm run lint && npm run format:check && npm run build"
  }
}

// Before Prettier (width 80, bracketSameLine: false)
<Button onClick={handleClick} disabled={isLoading} className="primary">
  Submit
</Button>

// After Prettier reformats to:
<Button
  onClick={handleClick}
  disabled={isLoading}
  className="primary"
>
  Submit
</Button>

// Disable a rule for one line
const value = someLib.getValue() // eslint-disable-line @typescript-eslint/no-explicit-any

// Disable for a block
/* eslint-disable react-hooks/exhaustive-deps */
useEffect(() => {
  // intentionally running only on mount
}, [])
/* eslint-enable react-hooks/exhaustive-deps */

// eslint.config.js — type-aware rules
export default tseslint.config(
  {
    extends: [
      js.configs.recommended,
      ...tseslint.configs.recommendedTypeChecked,  // type-aware variant
    ],
    languageOptions: {
      parserOptions: {
        project: true,          // use closest tsconfig.json
        tsconfigRootDir: import.meta.dirname,
      },
    },
    files: ['**/*.{ts,tsx}'],
    // ...
  }
)

// eslint.config.js
import a11y from 'eslint-plugin-jsx-a11y'

export default tseslint.config(
  // ... existing config ...
  {
    plugins: { 'jsx-a11y': a11y },
    rules: {
      ...a11y.configs.recommended.rules,
    },
  }
)

// eslint.config.js
import js from '@eslint/js'
import tseslint from 'typescript-eslint'
import reactHooks from 'eslint-plugin-react-hooks'
import reactRefresh from 'eslint-plugin-react-refresh'
import prettierConfig from 'eslint-config-prettier'

export default tseslint.config(
  { ignores: ['dist'] },
  {
    extends: [js.configs.recommended, ...tseslint.configs.recommended],
    files: ['**/*.{ts,tsx}'],
    plugins: {
      'react-hooks': reactHooks,
      'react-refresh': reactRefresh,
    },
    rules: {
      ...reactHooks.configs.recommended.rules,
      'react-refresh/only-export-components': ['warn', { allowConstantExport: true }],
    },
  },
  prettierConfig
)
